/**
 * ============================================================
 * 3D OBJECT EDITOR HELPER - Usage Instructions
 * ============================================================
 * 
 * This module provides a complete 3D object editor pattern for
 * Three.js-based level editors with property panels,
 * draggable objects, and customizable UI.
 * 
 * USAGE:
 * ------
 * 1. Include required HTML elements (see HTML STRUCTURE below)
 * 2. Initialize editState and editor functions
 * 3. Call setupEditorInteractions() to enable editing
 * 4. Use createPropertyPanel() for each object type
 * 
 * ============================================================
 * HTML STRUCTURE REQUIRED:
 * ============================================================
 * 
 * <!-- Edit Overlay Container -->
 * <div class="edit-overlay" id="edit-overlay">
 *     <!-- Toolbar -->
 *     <div class="edit-toolbar">
 *         <button id="btn-toggle-sidebar">EDITOR</button>
 *         <select id="object-type-select" class="object-dropdown">
 *             <option value="objectType">Object Name</option>
 *         </select>
 *         <button class="create-btn" id="btn-create-object">+ CREATE</button>
 *     </div>
 *     
 *     <!-- Instructions -->
 *     <div class="edit-instructions">
 *         Click to select • Drag objects to move • W/S to adjust height
 *     </div>
 *     
 *     <!-- Property Panel -->
 *     <div class="selected-info" id="selected-info">
 *         <h3 id="selected-name">Object</h3>
 *         <div id="selected-properties"></div>
 *     </div>
 * </div>
 * 
 * ============================================================
 * CSS REQUIRED:
 * ============================================================
 * 
 * .edit-overlay {
 *     position: absolute;
 *     top: 0; left: 0;
 *     width: 100%; height: 100%;
 *     pointer-events: none;
 *     z-index: 20;
 *     display: none;
 * }
 * .edit-overlay.visible { display: block; }
 * 
 * .edit-toolbar {
 *     position: absolute;
 *     top: 16px; left: 50%;
 *     transform: translateX(-50%);
 *     background: rgba(0,0,0,0.85);
 *     padding: 8px 16px;
 *     border-radius: 12px;
 *     display: flex;
 *     gap: 8px;
 *     pointer-events: auto;
 *     border: 2px solid rgba(255,255,255,0.2);
 * }
 * 
 * .selected-info {
 *     position: absolute;
 *     top: 80px; right: 16px;
 *     background: rgba(0,0,0,0.85);
 *     padding: 16px;
 *     border-radius: 8px;
 *     color: white;
 *     font-size: 14px;
 *     min-width: 200px;
 *     display: none;
 *     pointer-events: auto;
 * }
 * .selected-info.visible { display: block; }
 * .selected-info h3 {
 *     font-family: 'Bebas Neue', sans-serif;
 *     font-size: 24px;
 *     margin-bottom: 8px;
 *     color: #ffcc00;
 * }
 * .selected-info label {
 *     display: block;
 *     margin-top: 8px;
 *     font-size: 12px;
 *     color: rgba(255,255,255,0.7);
 * }
 * .selected-info input[type="range"] { width: 100%; }
 * .selected-info .value-display { color: white; }
 * 
 * .edit-instructions {
 *     position: absolute;
 *     bottom: 16px; left: 50%;
 *     transform: translateX(-50%);
 *     background: rgba(0,0,0,0.8);
 *     padding: 8px 16px;
 *     border-radius: 8px;
 *     color: white;
 *     font-size: 14px;
 *     pointer-events: none;
 * }
 * 
 * ============================================================
 * JAVASCRIPT REQUIRED:
 * ============================================================
 * 
 * // Edit state object (global)
 * let editState = {
 *     selectedObject: null,
 *     selectedType: null,
 *     selectedIndex: -1,
 *     isDragging: false,
 *     dragPlane: null,
 *     selectionHighlight: null,
 * };
 * 
 * // Array to hold all editible 3D objects
 * let allEditObjects = [];
 * 
 * // Three.js essentials
 * let scene, camera, renderer, raycaster, mouse;
 * 
 * // Call during initialization
 * function initEditor() {
 *     raycaster = new THREE.Raycaster();
 *     mouse = new THREE.Vector2();
 *     setupEditorInteractions();
 * }
 * 
 * ============================================================
 */

// ==================== EDIT STATE MANAGEMENT ====================

const EditorHelper = {
    editState: {
        selectedObject: null,
        selectedType: null,
        selectedIndex: -1,
        isDragging: false,
        dragPlane: null,
        selectionHighlight: null,
        lastDragX: 0,
        lastDragY: 0,
    },

    // Configuration for creating selection highlight
    highlightConfig: {
        color: 0xffff00,
        wireframeOpacity: 0.8,
        glowOpacity: 0.15,
        boxPadding: 0.2,
    },

    /**
     * Initialize the editor helper system
     * Call this in your Three.js init function
     */
    init: function(sceneRef, cameraRef, rendererRef) {
        this.scene = sceneRef;
        this.camera = cameraRef;
        this.renderer = rendererRef;
        this.raycaster = new THREE.Raycaster();
        this.mouse = new THREE.Vector2();
        this.dragPlane = new THREE.Plane(new THREE.Vector3(0, 1, 0), 0);

        // Bind event handlers
        this._boundHandlers = {
            click: this._handleClick.bind(this),
            mousedown: this._handleMouseDown.bind(this),
            mousemove: this._handleMouseMove.bind(this),
            mouseup: this._handleMouseUp.bind(this),
            keydown: this._handleKeyDown.bind(this),
            contextmenu: this._handleContextMenu.bind(this),
        };

        return this;
    },

    /**
     * Setup editor interaction handlers
     * Call this after the canvas is ready
     */
    setupInteractions: function(canvas) {
        if (!canvas) {
            console.error('EditorHelper: Canvas element required');
            return;
        }

        this.canvas = canvas;

        canvas.addEventListener('click', this._boundHandlers.click);
        canvas.addEventListener('mousedown', this._boundHandlers.mousedown);
        canvas.addEventListener('mousemove', this._boundHandlers.mousemove);
        canvas.addEventListener('mouseup', this._boundHandlers.mouseup);
        document.addEventListener('keydown', this._boundHandlers.keydown);
        canvas.addEventListener('contextmenu', this._boundHandlers.contextmenu);

        return this;
    },

    /**
     * Update the list of selectable objects
     * Call this when objects are added/removed
     */
    setSelectableObjects: function(objectArray) {
        this.selectableObjects = objectArray;
        return this;
    },

    // ----------------- EVENT HANDLERS -----------------

    _handleClick: function(e) {
        if (this.isPanning) return;

        const rect = this.canvas.getBoundingClientRect();
        this.mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
        this.mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;

        this.raycaster.setFromCamera(this.mouse, this.camera);

        if (!this.selectableObjects || this.selectableObjects.length === 0) return;

        const intersects = this.raycaster.intersectObjects(this.selectableObjects, true);

        if (intersects.length > 0) {
            let obj = intersects[0].object;
            while (obj && !obj.userData.type && obj.parent) {
                obj = obj.parent;
            }
            if (obj && obj.userData.type) {
                this.selectObject(obj);
            }
        } else {
            this.deselectObject();
        }
    },

    _handleMouseDown: function(e) {
        // Right-click for panning
        if (e.button === 2) {
            this.isPanning = true;
            this.lastPanX = e.clientX;
            this.lastPanY = e.clientY;
            return;
        }

        if (!this.editState.selectedObject) return;

        const rect = this.canvas.getBoundingClientRect();
        this.mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
        this.mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;

        this.raycaster.setFromCamera(this.mouse, this.camera);

        const intersects = this.raycaster.intersectObjects([this.editState.selectedObject], true);

        if (intersects.length > 0) {
            this.editState.isDragging = true;
            this.editState.lastDragX = e.clientX;
            this.editState.lastDragY = e.clientY;

            // Set drag plane at object height
            this.dragPlane.set(
                new THREE.Vector3(0, 1, 0),
                -this.editState.selectedObject.position.y
            );
        }
    },

    _handleMouseMove: function(e) {
        // Handle panning
        if (this.isPanning) {
            const deltaX = e.clientX - this.lastPanX;
            const deltaY = e.clientY - this.lastPanY;

            if (this.camera) {
                this.camera.position.x -= deltaX * 0.01;
                this.camera.position.z -= deltaY * 0.01;
            }

            this.lastPanX = e.clientX;
            this.lastPanY = e.clientY;
            return;
        }

        // Handle dragging
        if (!this.editState.isDragging || !this.editState.selectedObject) return;

        const rect = this.canvas.getBoundingClientRect();
        this.mouse.x = ((e.clientX - rect.left) / rect.width) * 2 - 1;
        this.mouse.y = -((e.clientY - rect.top) / rect.height) * 2 + 1;

        this.raycaster.setFromCamera(this.mouse, this.camera);

        const intersectPoint = new THREE.Vector3();
        this.raycaster.ray.intersectPlane(this.dragPlane, intersectPoint);

        if (intersectPoint) {
            const obj = this.editState.selectedObject;
            const type = this.editState.selectedType;
            const index = this.editState.selectedIndex;

            obj.position.x = intersectPoint.x;
            obj.position.z = intersectPoint.z;

            // Update config
            this._updateObjectPosition(type, index, obj.position);

            // Update highlight position
            if (this.editState.selectionHighlight) {
                const bbox = new THREE.Box3().setFromObject(obj);
                const center = new THREE.Vector3();
                bbox.getCenter(center);
                this.editState.selectionHighlight.position.copy(center);
            }

            // Update property panel
            this._updatePropertyPanel();
        }
    },

    _handleMouseUp: function(e) {
        if (e.button === 2) {
            this.isPanning = false;
        }
        this.editState.isDragging = false;
    },

    _handleKeyDown: function(e) {
        if (!this.editState.selectedObject) return;

        const key = e.key.toLowerCase();
        const yDelta = key === 'w' ? 0.1 : key === 's' ? -0.1 : 0;

        if (yDelta !== 0) {
            this.editState.selectedObject.position.y = Math.max(0.1, 
                this.editState.selectedObject.position.y + yDelta);

            // Update config
            const type = this.editState.selectedType;
            const index = this.editState.selectedIndex;
            this._updateObjectYPosition(type, index, 
                this.editState.selectedObject.position.y);

            // Update highlight
            if (this.editState.selectionHighlight) {
                this.editState.selectionHighlight.position.y = 
                    this.editState.selectedObject.position.y;
            }

            // Update panel
            this._updatePropertyPanel();
        }
    },

    _handleContextMenu: function(e) {
        e.preventDefault();
    },

    // ----------------- SELECTION -----------------

    /**
     * Select an object and show its property panel
     * @param {THREE.Object3D} object - The 3D object to select
     * @param {Object} config - The configuration object for this object type
     * @param {Function} propertyBuilder - Function to build property panel HTML
     */
    selectObject: function(object, config, propertyBuilder) {
        this.deselectObject();

        if (!object) return;

        this.editState.selectedObject = object;
        this.editState.selectedType = object.userData.type;
        this.editState.selectedIndex = object.userData.index;

        // Highlight with emissive
        if (object.material && object.material.emissive) {
            object.material.emissive.setHex(0x444400);
        }

        // Create selection highlight box
        this._createSelectionHighlight(object);

        // Show properties panel
        this._showPropertyPanel(object, config, propertyBuilder);

        return this;
    },

    /**
     * Deselect current object and hide property panel
     */
    deselectObject: function() {
        // Remove emissive highlight
        if (this.editState.selectedObject && 
            this.editState.selectedObject.material && 
            this.editState.selectedObject.material.emissive) {
            this.editState.selectedObject.material.emissive.setHex(0x000000);
        }

        // Remove selection highlight
        if (this.editState.selectionHighlight) {
            this.scene.remove(this.editState.selectionHighlight);
            this.editState.selectionHighlight.geometry.dispose();
            this.editState.selectionHighlight.material.dispose();
            this.editState.selectionHighlight = null;
        }

        // Clear state
        this.editState.selectedObject = null;
        this.editState.selectedType = null;
        this.editState.selectedIndex = -1;

        // Hide panel
        const infoPanel = document.getElementById('selected-info');
        if (infoPanel) {
            infoPanel.classList.remove('visible');
        }

        return this;
    },

    // ----------------- SELECTION HIGHLIGHT -----------------

    _createSelectionHighlight: function(object) {
        const bbox = new THREE.Box3().setFromObject(object);
        const size = new THREE.Vector3();
        bbox.getSize(size);
        const center = new THREE.Vector3();
        bbox.getCenter(center);

        const cfg = this.highlightConfig;

        // Wireframe box
        const highlightGeom = new THREE.BoxGeometry(
            size.x + cfg.boxPadding,
            size.y + cfg.boxPadding,
            size.z + cfg.boxPadding
        );
        const highlightMat = new THREE.MeshBasicMaterial({
            color: cfg.color,
            wireframe: true,
            transparent: true,
            opacity: cfg.wireframeOpacity,
        });

        this.editState.selectionHighlight = new THREE.Mesh(highlightGeom, highlightMat);
        this.editState.selectionHighlight.position.copy(center);
        this.scene.add(this.editState.selectionHighlight);

        // Glow box
        const glowGeom = new THREE.BoxGeometry(
            size.x + cfg.boxPadding + 0.1,
            size.y + cfg.boxPadding + 0.1,
            size.z + cfg.boxPadding + 0.1
        );
        const glowMat = new THREE.MeshBasicMaterial({
            color: cfg.color,
            transparent: true,
            opacity: cfg.glowOpacity,
            side: THREE.BackSide,
        });
        const glowMesh = new THREE.Mesh(glowGeom, glowMat);
        this.editState.selectionHighlight.add(glowMesh);
    },

    // ----------------- PROPERTY PANEL -----------------

    _showPropertyPanel: function(object, config, propertyBuilder) {
        const infoPanel = document.getElementById('selected-info');
        const nameEl = document.getElementById('selected-name');
        const propsEl = document.getElementById('selected-properties');

        if (!infoPanel || !nameEl || !propsEl) return;

        infoPanel.classList.add('visible');

        // Get object info
        const type = this.editState.selectedType;
        const index = this.editState.selectedIndex;

        // Set name
        nameEl.textContent = this._getObjectName(type, index);

        // Build properties HTML
        if (propertyBuilder) {
            propsEl.innerHTML = propertyBuilder(object, config, index, this);
        }
    },

    _updatePropertyPanel: function() {
        const propsEl = document.getElementById('selected-properties');
        if (!propsEl || !this.editState.selectedObject) return;

        const obj = this.editState.selectedObject;

        // Update position displays
        const xDisplay = propsEl.querySelector('.x-value-display');
        const yDisplay = propsEl.querySelector('.y-value-display');
        const zDisplay = propsEl.querySelector('.z-value-display');

        if (xDisplay) xDisplay.textContent = obj.position.x.toFixed(1);
        if (yDisplay) yDisplay.textContent = obj.position.y.toFixed(1);
        if (zDisplay) zDisplay.textContent = obj.position.z.toFixed(1);
    },

    _getObjectName: function(type, index) {
        const typeNames = {
            kitkat: 'KitKat',
            crate: 'Crate',
            camera: 'Camera',
            laser: 'Laser',
            lava: 'Lava',
            key: 'Key',
            door: 'Door',
            switch: 'Switch',
            portal: 'Portal',
            platform: 'Platform',
            wall: 'Wall',
            pit: 'Pit',
        };

        const name = typeNames[type] || type;
        return index >= 0 ? `${name} #${index + 1}` : name;
    },

    _updateObjectPosition: function(type, index, position) {
        // Override in subclass or pass config
    },

    _updateObjectYPosition: function(type, index, y) {
        // Override in subclass or pass config
    },

    // ----------------- PROPERTY PANEL BUILDERS -----------------

    /**
     * Create common action buttons HTML
     */
    createActionButtons: function() {
        return `
            <div style="display: flex; gap: 8px; margin-top: 12px;">
                <button id="btn-duplicate-object" style="flex: 1; padding: 8px; 
                    background: #1976d2; color: white; border: none; 
                    border-radius: 6px; cursor: pointer; font-weight: 600;">
                    📋 Duplicate
                </button>
                <button id="btn-delete-object" style="flex: 1; padding: 8px; 
                    background: #d32f2f; color: white; border: none; 
                    border-radius: 6px; cursor: pointer; font-weight: 600;">
                    🗑️ Delete
                </button>
            </div>`;
    },

    /**
     * Create position display row
     */
    createPositionDisplay: function(object) {
        return `
            <label>Position X: <span class="value-display x-value-display">${object.position.x.toFixed(1)}</span></label>
            <label>Position Y: <span class="value-display y-value-display">${object.position.y.toFixed(1)}</span></label>
            <label>Position Z: <span class="value-display z-value-display">${object.position.z.toFixed(1)}</span></label>`;
    },

    /**
     * Create a slider input
     */
    createSlider: function(id, label, min, max, step, value, onChange) {
        const valId = `${id}-val`;
        return `
            <label>${label}</label>
            <input type="range" id="${id}" min="${min}" max="${max}" step="${step}" value="${value}">
            <span class="value-display" id="${valId}">${value}</span>`;
    },

    /**
     * Create a color picker
     */
    createColorPicker: function(id, value) {
        return `
            <input type="color" id="${id}" value="${value}" 
                style="width: 100%; height: 30px; margin-top: 4px; 
                border-radius: 4px; border: none; cursor: pointer;">`;
    },

    /**
     * Create a number input
     */
    createNumberInput: function(id, label, value, min, max, step) {
        return `
            <label>${label}</label>
            <input type="number" id="${id}" value="${value}" min="${min || 0}" 
                max="${max || 100}" step="${step || 1}" 
                style="width: 100%; padding: 6px; margin-top: 4px; 
                border-radius: 4px; background: #333; color: white; 
                border: 1px solid #555;">`;
    },

    /**
     * Create a select dropdown
     */
    createSelect: function(id, label, options, selectedValue) {
        const opts = options.map(opt => 
            `<option value="${opt.value}" ${opt.value === selectedValue ? 'selected' : ''}>
                ${opt.label}
            </option>`
        ).join('');

        return `
            <label>${label}</label>
            <select id="${id}" style="width: 100%; padding: 6px; margin-top: 4px; 
                border-radius: 4px; background: #333; color: white; 
                border: 1px solid #555;">
                ${opts}
            </select>`;
    },

    /**
     * Create a checkbox
     */
    createCheckbox: function(id, label, checked) {
        return `
            <label style="display: flex; align-items: center; gap: 8px; margin-top: 8px;">
                <input type="checkbox" id="${id}" ${checked ? 'checked' : ''}>
                <span>${label}</span>
            </label>`;
    },

    // ----------------- SCALING METHODS -----------------

    /**
     * Set selection highlight color
     */
    setHighlightColor: function(color) {
        this.highlightConfig.color = color;
        return this;
    },

    /**
     * Set selection highlight opacity
     */
    setHighlightOpacity: function(wireframe, glow) {
        if (wireframe !== undefined) this.highlightConfig.wireframeOpacity = wireframe;
        if (glow !== undefined) this.highlightConfig.glowOpacity = glow;
        return this;
    },

    /**
     * Set selection box padding
     */
    setBoxPadding: function(padding) {
        this.highlightConfig.boxPadding = padding;
        return this;
    },
};

// ==================== PROPERTY PANEL TEMPLATES ====================

/**
 * Pre-built property panel builders for common object types
 */
const PropertyPanelTemplates = {
    /**
     * Basic collectible (e.g., coins, items)
     * Shows position only, read-only
     */
    collectible: function(object, config, index) {
        return `
            ${PropertyPanelTemplates.position(object)}
            <p style="margin-top: 8px; font-size: 12px; opacity: 0.7;">
                Drag to reposition
            </p>
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Position display
     */
    position: function(object) {
        return `
            <label>Position X: <span class="value-display">${object.position.x.toFixed(1)}</span></label>
            <label>Position Y: <span class="value-display">${object.position.y.toFixed(1)}</span></label>
            <label>Position Z: <span class="value-display">${object.position.z.toFixed(1)}</span></label>`;
    },

    /**
     * Sizable object (crates, platforms)
     */
    sizeable: function(object, config, index, options) {
        const cfg = config[index];
        return `
            ${PropertyPanelTemplates.position(object)}
            ${EditorHelper.createSlider('obj-size', 'Size', options.minSize, options.maxSize, 
                options.step || 0.1, cfg.size, 
                `document.getElementById('obj-size-val').textContent = e.target.value;` +
                (options.onChange || ''))}
            <p style="margin-top: 8px; font-size: 12px; opacity: 0.7;">
                Drag to move • W/S adjust height
            </p>
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Rotatable object (doors, walls)
     */
    rotatable: function(object, config, index, options) {
        const cfg = config[index];
        const rotationDegrees = (cfg.rotation || 0) * 45;
        return `
            ${PropertyPanelTemplates.position(object)}
            ${EditorHelper.createSlider('obj-width', 'Width', options.minWidth, options.maxWidth, 
                0.5, cfg.width)}
            ${EditorHelper.createSlider('obj-height', 'Height', options.minHeight, options.maxHeight, 
                0.5, cfg.height)}
            ${EditorHelper.createSlider('obj-rotation', 'Rotation (45°)', 0, 7, 1, 
                cfg.rotation || 0)}
            <p style="margin-top: 8px; font-size: 12px; opacity: 0.7;">
                Rotates in 45° increments
            </p>
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Color-customizable object
     */
    colored: function(object, config, index) {
        const cfg = config[index];
        return `
            ${PropertyPanelTemplates.position(object)}
            <label>Color</label>
            ${EditorHelper.createColorPicker('obj-color', cfg.color)}
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Security camera with viewing cone
     */
    camera: function(object, config, index, options) {
        const cfg = config[index];
        return `
            ${EditorHelper.createSlider('cam-rotation', 'Start Rotation', -3.14, 3.14, 
                0.1, cfg.startAngle)}
            ${EditorHelper.createSlider('cam-speed', 'Rotation Speed', 0.1, 2, 0.1, 
                cfg.rotationSpeed)}
            ${EditorHelper.createSlider('cam-range', 'Detection Range', 3, 10, 0.5, cfg.range)}
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Laser grid
     */
    laser: function(object, config, index) {
        const cfg = config[index];
        return `
            ${EditorHelper.createSlider('laser-width', 'Width', 1, 16, 0.5, cfg.width)}
            ${EditorHelper.createSlider('laser-height', 'Height', 1, 4, 0.5, cfg.height)}
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Switch/Button with target
     */
    switch: function(object, config, index, options) {
        const cfg = config[index];
        const laserCount = options.laserCount || 0;
        const doorCount = options.doorCount || 0;

        return `
            ${EditorHelper.createSelect('switch-target', 'Target Type', [
                { value: 'laser', label: `Laser (${laserCount} available)` },
                { value: 'door', label: `Door (${doorCount} available)` },
            ], cfg.targetType)}
            ${EditorHelper.createNumberInput('switch-index', 'Target Index', cfg.targetIndex, 0, 99, 1)}
            ${EditorHelper.createColorPicker('switch-color', cfg.color)}
            ${EditorHelper.createCheckbox('switch-activated', 'Start Activated', cfg.activated)}
            ${EditorHelper.createActionButtons()}`;
    },

    /**
     * Portal
     */
    portal: function(object, config, index, options) {
        const cfg = config[index];
        const isBlue = cfg.color === 'blue';
        const portalCount = options.portalCount || 2;

        return `
            <label>Color: <span style="color: ${isBlue ? '#00aaff' : '#ffaa00'}; 
                font-weight: bold;">${cfg.color.toUpperCase()}</span></label>
            ${EditorHelper.createSlider('portal-height', 'Height', 0.5, 4, 0.1, cfg.y)}
            ${EditorHelper.createSlider('portal-rotation', 'Rotation', 0, 6.28, 0.1, cfg.rotation)}
            ${EditorHelper.createNumberInput('portal-linked', 'Linked Portal #', 
                cfg.linkedTo || 0, 0, portalCount - 1, 1)}
            ${EditorHelper.createSelect('portal-color', 'Toggle Color', [
                { value: 'blue', label: 'Blue' },
