// ==================== DRAGGABLE MIXIN ====================

/**
 * Mixin to make any object draggable
 * Usage: call Draggable.init(mesh, config, onUpdate)
 */
const Draggable = {
    isDraggable: true,

    init: function(mesh, config, onUpdate) {
        this.mesh = mesh;
        this.config = config;
        this.onUpdate = onUpdate;

        mesh.userData.draggable = true;
        mesh.userData.dragConfig = config;

        return this;
    },

    setPosition: function(x, y, z) {
        this.mesh.position.set(x, y, z);
        if (this.config) {
            this.config.x = x;
            this.config.y = y;
            this.config.z = z;
        }
        if (this.onUpdate) this.onUpdate(this.config);
    },

    getPosition: function() {
        return this.mesh.position.clone();
    },
};

